<script setup>import{reactive,ref}from'vue';import axios from'axios';import PageHeader from'../components/PageHeader.vue';import{useAuthStore}from'../stores/auth';const auth=useAuthStore(),form=reactive({current_password:'',password:'',password_confirmation:''}),message=ref('');async function save(){try{message.value=(await axios.put('/api/auth/password',form)).data.message;Object.assign(form,{current_password:'',password:'',password_confirmation:''})}catch(e){message.value=e.response?.data?.message||Object.values(e.response?.data?.errors||{})[0]?.[0]||'Unable to update password.'}}</script>
<template><PageHeader title="Settings" subtitle="Account identity and security"/><div class="two-col"><section class="panel profile"><img src="/media/Nenial.jpg"><h2>{{auth.user.name}}</h2><p>{{auth.user.email}}</p><span class="tag">{{auth.user.role}}</span></section><form class="panel stack" @submit.prevent="save"><div class="panel-head"><h2>Change password</h2></div><label>Current password<input v-model="form.current_password" type="password" required></label><label>New password<input v-model="form.password" type="password" minlength="8" required></label><label>Confirm new password<input v-model="form.password_confirmation" type="password" required></label><small>Use at least 8 characters with uppercase, lowercase, and a number.</small><p v-if="message" class="notice">{{message}}</p><button class="btn primary">Update password</button></form></div></template>
